import{c as a,Q as i,j as t,m as l}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"出使摩纳哥领主","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/155-出使摩纳哥领主.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/155-出使摩纳哥领主.md"}'),p={name:"research/machiavelli/machiavelli/diplomatic/lower/155-出使摩纳哥领主.md"};function r(c,e,o,_,s,m){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="出使摩纳哥领主" tabindex="-1">出使摩纳哥领主 <a class="header-anchor" href="#出使摩纳哥领主" aria-label="Permalink to &quot;出使摩纳哥领主&quot;">​</a></h1><p>出使摩纳哥领主</p><p>1511年5月</p><p>特许状和通行证</p><p>佛罗伦萨共和国自由十人委员会</p><p>敬启者：本信持有人是我们深爱的公民和秘书尼科洛 · 马基雅维利阁 下，我们派遣他为我共和国之事务出访摩纳哥领主阁下。 是故，我们恳请我共和国的一切朋友、同盟及被保护人，并命令我属 民，向这位尼科洛提供一切有利于他履行使命的及时支援和协助，为此我 们将衷心感激一切朋友、同盟及被保护人，并给予我属民以最高的赞扬。</p><p>发自佛罗伦萨市政宫，1511年5月12日</p><p>拟与摩纳哥领主卢西亚诺 ·格里马尔迪缔结之协议的目标</p><p>大佛罗伦萨共和国与摩纳哥国君陛下之间维持真诚深厚的友谊，接下 来10年间，如同对待至交好友一样对待对方及对方的军队、属民、船只、 货物、商人和其他一切事物。 细则。在规定时期，该国君的船只、人员和货物自由往来和居留于大 佛罗伦萨共和国各处港口，无需安全通行证，他们可以停留在各处港口补 充面包、淡水、食物及一切所需的物品，与佛罗伦萨的船只和人员同等对 待；为这些事物支付的价值同于别的佛罗伦萨人应支付者，所缴纳的关税 亦同于别的佛罗伦萨人应缴纳者。反过来，摩纳哥国君在他的各处港口， 对待大佛罗伦萨共和国的船只、人员、货物以及她的一切属民，亦遵行同</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p>',10)])])}const h=a(p,[["render",r]]);export{d as __pageData,h as default};
